const outputStr = $input.first().json.text || $input.first().json.output || $input.first().json;
let parsed = {};
try {
  let cleanStr = typeof outputStr === 'string' ? outputStr : JSON.stringify(outputStr);

  // Extract from the first { to the last }
  const firstBrace = cleanStr.indexOf('{');
  const lastBrace = cleanStr.lastIndexOf('}');

  if (firstBrace !== -1 && lastBrace !== -1) {
      cleanStr = cleanStr.substring(firstBrace, lastBrace + 1);
  }

  // Strip control chars that break JSON.parse
  cleanStr = cleanStr.replace(/[\x00-\x1F]/g, "");

  parsed = JSON.parse(cleanStr);

  // Force structures to exist
  if (!parsed.verification_metadata) parsed.verification_metadata = { pass: true };
  if (!parsed.claim_verification) parsed.claim_verification = [];

  // Enforce leniency programmatically: Only fail if there is a 'FABRICATED' claim.
  const hasFabricated = parsed.claim_verification.some(c => c.verdict === 'FABRICATED');
  if (!hasFabricated && parsed.verification_metadata.pass === false) {
      // Override pedantic LLM
      parsed.verification_metadata.pass = true;
      parsed.overall_assessment = "Passed by programmatic leniency guard (no fabricated claims found).";
  }

} catch (e) {
  parsed = { 
    verification_metadata: { pass: false }, 
    overall_assessment: 'JSON Parse Error: ' + e.message, 
    claim_verification: [],
    parse_error: true
  };
}

const runIndex = $runIndex || 0;
return [{\n  json: { ...parsed, retry_count: runIndex, raw_output: outputStr }\n}];

